/**
 * @summary Upload a file for a project
 */
export const getUploadFileUrl = (projectId: number) => {
  return `/api/projects/${projectId}/files`;
};

export const uploadFile = async (
  projectId: number,
  uploadFileBody: UploadFileBody,
  options?: RequestInit,
): Promise<ProjectFile> => {
  const formData = new FormData();
  formData.append(`file`, uploadFileBody.file);
  formData.append(`category`, uploadFileBody.category);
  if (
    uploadFileBody.description !== undefined &&
    uploadFileBody.description !== null
  ) {
    formData.append(`description`, uploadFileBody.description);
  }

  return customFetch<ProjectFile>(getUploadFileUrl(projectId), {
    ...options,
    method: "POST",
    body: formData,
  });
};

